#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_N 335
#define MAX_M 335
#define MAX_Q 105

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int N, M, Q;
    scanf("%d %d %d", &N, &M, &Q);
    int H[N][M];
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < M; j++) {
            scanf("%d", &H[i][j]);
        }
    }
    for (int q = 0; q < Q; q++) {
        int G;
        scanf("%d", &G);
        int triangles[N * M];
        int count = 0;
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                for (int k = i; k < N; k++) {
                    for (int l = j; l < M; l++) {
                        if ((k - i) == (l - j)) {
                            int hungriness = 0;
                            for (int x = i; x <= k; x++) {
                                for (int y = j; y <= l; y++) {
                                    hungriness += H[x][y];
                                }
                            }
                            triangles[count++] = hungriness;
                        }
                    }
                }
            }
        }
        qsort(triangles, count, sizeof(int), compare);
        int fed = 0;
        for (int i = 0; i < count; i++) {
            if (G >= triangles[i]) {
                G -= triangles[i];
                fed++;
            } else {
                break;
            }
        }
        printf("%d\n", fed);
    }
    return 0;
}

