            int G = sc.nextInt();
            int[] triangles = new int[N * M];
            int count = 0;
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < M; j++) {
                    for (int k = i; k < N; k++) {
                        for (int l = j; l < M; l++) {
                            if ((k - i) == (l - j)) {
                                int hungriness = 0;
                                for (int x = i; x <= k; x++) {
                                    for (int y = j; y <= l; y++) {
                                        hungriness += H[x][y];
                                    }
                                }
                                triangles[count++] = hungriness;
                            }
                        }
                    }
                }
            }
            Arrays.sort(triangles, 0, count);
